  "let",
  "var",
  "return",
  "if",
  "else",
  "while",
  "true",
  "false",
  "struct",
  "enum",
  "match",
  "mut",
  "import",
  "from",
  "break",
  "continue",
  "as",
  "trait",
  "impl",
  "for",
  "in",
  "unsafe",
  "move",
  "null",
  "is",
  "type",
  "interface",
  "requires",
  "ensures",
  "invariant"
